def count_vowels(s):
    """Count the number of vowels (a, e, i, o, u) in a string, considering only lowercase vowels."""
    if not isinstance(s, str):
        return 0
    vowels = set('aeiou')
    count = 0
    for char in s:
        if char in vowels:
            count += 1
    return count
